    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrs_steeplechase::{jjrs_SteeplechaseEntry, jjrs_get_entries, jjrs_ReinArgs};
    13→use serde::Serialize;
    14→use std::fs;
    15→
    16→// ============================================================================
    17→// Muster - List all Heats with summary information
    18→// ============================================================================
    19→
    20→/// Arguments for muster command
    21→#[derive(Debug)]
    22→pub struct jjrq_MusterArgs {
    23→    pub file: std::path::PathBuf,
    24→    pub status: Option<HeatStatus>,
    25→}
    26→
    27→/// Run the muster command - list Heats as TSV
    28→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    29→    let gallops = match Gallops::jjrg_load(&args.file) {
    30→        Ok(g) => g,
    31→        Err(e) => {
    32→            eprintln!("jjx_muster: error: {}", e);
    33→            return 1;
    34→        }
    35→    };
    36→
    37→    for (key, heat) in &gallops.heats {
    38→        // Apply status filter if provided
    39→        if let Some(ref filter_status) = args.status {
    40→            if &heat.status != filter_status {
    41→                continue;
    42→            }
    43→        }
    44→
    45→        let pace_count = heat.paces.len();
    46→        let status_str = match heat.status {
    47→            HeatStatus::Current => "current",
    48→            HeatStatus::Retired => "retired",
    49→        };
    50→
    51→        println!("{}\t{}\t{}\t{}", key, heat.silks, status_str, pace_count);
    52→    }
    53→
    54→    0
    55→}
