    58→// Saddle - Return context needed to saddle up on a Heat
    59→// ============================================================================
    60→
    61→/// Arguments for saddle command
    62→#[derive(Debug)]
    63→pub struct jjrq_SaddleArgs {
    64→    pub file: std::path::PathBuf,
    65→    pub firemark: Firemark,
    66→}
    67→
    68→/// Output structure for saddle command
    69→#[derive(Serialize)]
    70→pub(crate) struct zjjrq_SaddleOutput {
    71→    pub(crate) heat_silks: String,
    72→    pub(crate) paddock_file: String,
    73→    pub(crate) paddock_content: String,
    74→    #[serde(skip_serializing_if = "Option::is_none")]
    75→    pub(crate) pace_coronet: Option<String>,
    76→    #[serde(skip_serializing_if = "Option::is_none")]
    77→    pub(crate) pace_silks: Option<String>,
    78→    #[serde(skip_serializing_if = "Option::is_none")]
    79→    pub(crate) pace_state: Option<String>,
    80→    #[serde(skip_serializing_if = "Option::is_none")]
    81→    pub(crate) spec: Option<String>,
    82→    #[serde(skip_serializing_if = "Option::is_none")]
    83→    pub(crate) direction: Option<String>,
    84→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
    85→}
    86→
    87→/// Run the saddle command - return Heat context
    88→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
    89→    let gallops = match Gallops::jjrg_load(&args.file) {
    90→        Ok(g) => g,
    91→        Err(e) => {
    92→            eprintln!("jjx_saddle: error: {}", e);
    93→            return 1;
    94→        }
    95→    };
    96→
    97→    let heat_key = args.firemark.jjrf_display();
    98→    let heat = match gallops.heats.get(&heat_key) {
    99→        Some(h) => h,
   100→        None => {
   101→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   102→            return 1;
   103→        }
   104→    };
   105→
   106→    // Read paddock file content
   107→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   108→        Ok(content) => content,
   109→        Err(e) => {
   110→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   111→            return 1;
   112→        }
   113→    };
   114→
   115→    // Get recent steeplechase entries
   116→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   117→        firemark: args.firemark.jjrf_as_str().to_string(),
   118→        limit: 10,
   119→    }).unwrap_or_default();
   120→
   121→    // Find first actionable pace (rough or bridled)
   122→    let mut output = zjjrq_SaddleOutput {
   123→        heat_silks: heat.silks.clone(),
   124→        paddock_file: heat.paddock_file.clone(),
   125→        paddock_content,
   126→        pace_coronet: None,
   127→        pace_silks: None,
   128→        pace_state: None,
   129→        spec: None,
   130→        direction: None,
   131→        recent_work,
   132→    };
   133→
   134→    for coronet_key in &heat.order {
   135→        if let Some(pace) = heat.paces.get(coronet_key) {
   136→            if let Some(tack) = pace.tacks.first() {
   137→                match tack.state {
   138→                    PaceState::Rough | PaceState::Bridled => {
   139→                        output.pace_coronet = Some(coronet_key.clone());
   140→                        output.pace_silks = Some(tack.silks.clone());
   141→                        output.pace_state = Some(match tack.state {
   142→                            PaceState::Rough => "rough".to_string(),
   143→                            PaceState::Bridled => "bridled".to_string(),
   144→                            _ => unreachable!(),
   145→                        });
   146→                        output.spec = Some(tack.text.clone());
   147→                        if tack.state == PaceState::Bridled {
   148→                            output.direction = tack.direction.clone();
   149→                        }
   150→                        break;
   151→                    }
   152→                    _ => continue,
   153→                }
   154→            }
   155→        }
   156→    }
   157→
   158→    // Output JSON
   159→    match serde_json::to_string_pretty(&output) {
   160→        Ok(json) => {
   161→            println!("{}", json);
   162→            0
   163→        }
   164→        Err(e) => {
   165→            eprintln!("jjx_saddle: error serializing output: {}", e);
   166→            1
   167→        }
   168→    }
   169→}
