   171→// ============================================================================
   172→// Parade - Display comprehensive Heat status for project review
   173→// ============================================================================
   174→
   175→/// Output format modes for parade command
   176→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   177→pub enum jjrq_ParadeFormat {
   178→    /// One line per pace: [state] silks (₢coronet)
   179→    Overview,
   180→    /// Numbered list: N. [state] silks (₢coronet)
   181→    Order,
   182→    /// Full tack text for one pace (requires --pace)
   183→    Detail,
   184→    /// Paddock + all paces with tack text (default)
   185→    #[default]
   186→    Full,
   187→}
   188→
   189→/// Arguments for parade command
   190→#[derive(Debug)]
   191→pub struct jjrq_ParadeArgs {
   192→    pub file: std::path::PathBuf,
   193→    pub firemark: Firemark,
   194→    pub format: jjrq_ParadeFormat,
   195→    pub pace: Option<String>,
   196→    pub remaining: bool,
   197→}
   198→
   199→/// Run the parade command - display comprehensive Heat status
   200→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   201→    // Validate: detail format requires --pace
   202→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   203→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   204→        return 1;
   205→    }
   206→
   207→    let gallops = match Gallops::jjrg_load(&args.file) {
   208→        Ok(g) => g,
   209→        Err(e) => {
   210→            eprintln!("jjx_parade: error: {}", e);
   211→            return 1;
   212→        }
   213→    };
   214→
   215→    let heat_key = args.firemark.jjrf_display();
   216→    let heat = match gallops.heats.get(&heat_key) {
   217→        Some(h) => h,
   218→        None => {
   219→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   220→            return 1;
   221→        }
   222→    };
   223→
   224→    match args.format {
   225→        jjrq_ParadeFormat::Overview => {
   226→            for coronet_key in &heat.order {
   227→                if let Some(pace) = heat.paces.get(coronet_key) {
   228→                    if let Some(tack) = pace.tacks.first() {
   229→                        // Skip complete/abandoned if --remaining
   230→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   231→                            continue;
   232→                        }
   233→                        let state_str = zjjrq_pace_state_str(&tack.state);
   234→                        println!("[{}] {} ({})", state_str, tack.silks, coronet_key);
   235→                    }
   236→                }
   237→            }
   238→        }
   239→        jjrq_ParadeFormat::Order => {
   240→            let mut num = 0;
   241→            for coronet_key in &heat.order {
   242→                if let Some(pace) = heat.paces.get(coronet_key) {
   243→                    if let Some(tack) = pace.tacks.first() {
   244→                        // Skip complete/abandoned if --remaining
   245→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   246→                            continue;
   247→                        }
   248→                        num += 1;
   249→                        let state_str = zjjrq_pace_state_str(&tack.state);
   250→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   251→                    }
   252→                }
   253→            }
   254→        }
   255→        jjrq_ParadeFormat::Detail => {
   256→            let target_coronet = args.pace.as_ref().unwrap();
   257→            let pace = match heat.paces.get(target_coronet) {
   258→                Some(p) => p,
   259→                None => {
   260→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", target_coronet, heat_key);
   261→                    return 1;
   262→                }
   263→            };
   264→            if let Some(tack) = pace.tacks.first() {
   265→                let state_str = zjjrq_pace_state_str(&tack.state);
   266→                println!("Pace: {} ({})", tack.silks, target_coronet);
   267→                println!("State: {}", state_str);
   268→                println!("Heat: {}", heat_key);
   269→                println!();
   270→                println!("{}", tack.text);
   271→                if let Some(ref direction) = tack.direction {
   272→                    println!();
   273→                    println!("Direction: {}", direction);
   274→                }
   275→            }
   276→        }
   277→        jjrq_ParadeFormat::Full => {
   278→            // Read paddock file content
   279→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   280→                Ok(content) => content,
   281→                Err(e) => {
   282→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   283→                    return 1;
   284→                }
   285→            };
   286→
   287→            let status_str = match heat.status {
   288→                HeatStatus::Current => "current",
   289→                HeatStatus::Retired => "retired",
   290→            };
   291→
   292→            println!("Heat: {} ({})", heat.silks, heat_key);
   293→            println!("Status: {}", status_str);
   294→            println!("Created: {}", heat.creation_time);
   295→            println!();
   296→            println!("## Paddock");
   297→            println!();
   298→            println!("{}", paddock_content);
   299→            println!();
   300→            println!("## Paces");
   301→            println!();
   302→
   303→            for coronet_key in &heat.order {
   304→                if let Some(pace) = heat.paces.get(coronet_key) {
   305→                    if let Some(tack) = pace.tacks.first() {
   306→                        // Skip complete/abandoned if --remaining
   307→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   308→                            continue;
   309→                        }
   310→                        let state_str = zjjrq_pace_state_str(&tack.state);
   311→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   312→                        println!();
   313→                        println!("{}", tack.text);
   314→                        if let Some(ref direction) = tack.direction {
   315→                            println!();
   316→                            println!("**Direction:** {}", direction);
   317→                        }
   318→                        println!();
   319→                    }
   320→                }
   321→            }
   322→        }
   323→    }
   324→
   325→    0
   326→}
   327→
   328→/// Helper to convert PaceState to display string
   329→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   330→    match state {
   331→        PaceState::Rough => "rough",
   332→        PaceState::Bridled => "bridled",
   333→        PaceState::Complete => "complete",
   334→        PaceState::Abandoned => "abandoned",
   335→    }
   336→}
   337→
   338→// ============================================================================
   339→// Retire - Extract complete Heat data for archival trophy
   340→// ============================================================================
   341→
   342→/// Arguments for retire command
   343→#[derive(Debug)]
   344→pub struct jjrq_RetireArgs {
   345→    pub file: std::path::PathBuf,
   346→    pub firemark: Firemark,
   347→}
   348→
   349→/// Output structure for retire command
   350→#[derive(Serialize)]
   351→pub(crate) struct zjjrq_RetireOutput {
   352→    pub(crate) firemark: String,
   353→    pub(crate) silks: String,
   354→    pub(crate) created: String,
   355→    pub(crate) status: String,
   356→    pub(crate) paddock_file: String,
   357→    pub(crate) paddock_content: String,
   358→    pub(crate) paces: Vec<zjjrq_RetirePace>,
   359→    // TODO: steeplechase array from jjx_rein
   360→    // steeplechase: Vec<SteeplechaseEntry>,
   361→}
   362→
   363→/// Pace structure for retire output (full tack history)
   364→#[derive(Serialize)]
   365→pub(crate) struct zjjrq_RetirePace {
   366→    pub(crate) coronet: String,
   367→    pub(crate) silks: String,
   368→    pub(crate) tacks: Vec<zjjrq_RetireTack>,
   369→}
   370→
   371→/// Tack structure for retire output
   372→#[derive(Serialize)]
   373→pub(crate) struct zjjrq_RetireTack {
   374→    pub(crate) ts: String,
   375→    pub(crate) state: String,
   376→    pub(crate) text: String,
   377→    #[serde(skip_serializing_if = "Option::is_none")]
   378→    pub(crate) direction: Option<String>,
   379→}
   380→
   381→/// Run the retire command - extract complete Heat data for archival
   382→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   383→    let gallops = match Gallops::jjrg_load(&args.file) {
   384→        Ok(g) => g,
   385→        Err(e) => {
   386→            eprintln!("jjx_retire: error: {}", e);
   387→            return 1;
   388→        }
   389→    };
   390→
   391→    let heat_key = args.firemark.jjrf_display();
   392→    let heat = match gallops.heats.get(&heat_key) {
   393→        Some(h) => h,
   394→        None => {
   395→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   396→            return 1;
   397→        }
   398→    };
   399→
   400→    // Read paddock file content
   401→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   402→        Ok(content) => content,
   403→        Err(e) => {
   404→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   405→            return 1;
   406→        }
   407→    };
   408→
   409→    // Build paces array with full tack history, ordered per Heat's order array
   410→    let mut paces = Vec::new();
   411→    for coronet_key in &heat.order {
   412→        if let Some(pace) = heat.paces.get(coronet_key) {
   413→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   414→                zjjrq_RetireTack {
   415→                    ts: tack.ts.clone(),
   416→                    state: match tack.state {
   417→                        PaceState::Rough => "rough".to_string(),
   418→                        PaceState::Bridled => "bridled".to_string(),
   419→                        PaceState::Complete => "complete".to_string(),
   420→                        PaceState::Abandoned => "abandoned".to_string(),
   421→                    },
   422→                    text: tack.text.clone(),
   423→                    direction: tack.direction.clone(),
   424→                }
   425→            }).collect();
   426→
   427→            paces.push(zjjrq_RetirePace {
   428→                coronet: coronet_key.clone(),
   429→                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
   430→                tacks,
   431→            });
   432→        }
   433→    }
   434→
   435→    let output = zjjrq_RetireOutput {
   436→        firemark: heat_key.clone(),
   437→        silks: heat.silks.clone(),
   438→        created: heat.creation_time.clone(),
   439→        status: match heat.status {
   440→            HeatStatus::Current => "current".to_string(),
   441→            HeatStatus::Retired => "retired".to_string(),
   442→        },
   443→        paddock_file: heat.paddock_file.clone(),
   444→        paddock_content,
   445→        paces,
   446→        // TODO: Call jjx_rein internally to get steeplechase entries
   447→    };
   448→
   449→    // Output JSON
   450→    match serde_json::to_string_pretty(&output) {
   451→        Ok(json) => {
   452→            println!("{}", json);
   453→            0
   454→        }
   455→        Err(e) => {
   456→            eprintln!("jjx_retire: error serializing output: {}", e);
   457→            1
   458→        }
   459→    }
   460→}
