                    direction: tack.direction.clone(),
                }
            }).collect();

            paces.push(zjjrq_RetirePace {
                coronet: coronet_key.clone(),
                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
                tacks,
